using System;using System.Collections.Generic;using System.Reflection;using BgCommon.UI.Designer.Plugins;using UIDesignerDemo.Plugins;using Xunit;namespace UIDesignerDemo.Tests{    public class PluginSystemTests    {        [Fact]        public void BasicControlsPlugin_ShouldImplementInterfaceCorrectly()        {            // Arrange            var plugin = new BasicControlsPlugin();                        // Act & Assert            Assert.Equal("基础控件插件", plugin.Name);            Assert.Equal("1.0.0", plugin.Version);            Assert.Equal("UIDesignerDemo", plugin.Author);            Assert.Equal("提供基础WPF控件的插件", plugin.Description);            Assert.Equal("基础控件", plugin.Category);        }                [Fact]        public void BasicControlsPlugin_ShouldReturnValidComponentTypes()        {            // Arrange            var plugin = new BasicControlsPlugin();                        // Act            var componentTypes = plugin.GetComponentTypes();                        // Assert            Assert.NotNull(componentTypes);            Assert.NotEmpty(componentTypes);            Assert.Contains(typeof(System.Windows.Controls.Button), componentTypes);            Assert.Contains(typeof(System.Windows.Controls.TextBox), componentTypes);        }                [Fact]        public void PluginManager_ShouldRegisterAndManagePlugins()        {            // Arrange            var context = new ICSharpCode.WpfDesign.DesignContext();            var pluginManager = new PluginManager(context);            var plugin = new BasicControlsPlugin();                        // Act            pluginManager.RegisterPlugin(plugin);                        // Assert            Assert.Single(pluginManager.Plugins);            Assert.Equal(plugin, pluginManager.Plugins[0]);        }                [Fact]        public void PluginManager_ShouldDiscoverPluginsFromAssembly()        {            // Arrange            var context = new ICSharpCode.WpfDesign.DesignContext();            var pluginManager = new PluginManager(context);            var assembly = Assembly.GetExecutingAssembly();                        // Act            var method = typeof(PluginManager).GetMethod("DiscoverPluginsFromAssembly",                 BindingFlags.NonPublic | BindingFlags.Instance);            method.Invoke(pluginManager, new object[] { assembly });                        // Assert            Assert.NotEmpty(pluginManager.Plugins);        }    }}